1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return an empty array when given an empty array (no living cells)", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	
9	  it("Rule 1 (Underpopulation): a single live cell [(0,0)] dies → []", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	
13	  it("Rule 1 (Underpopulation): two adjacent cells [(0,1), (1,1)] each have 1 neighbor and die → []", () => {
14	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
15	  });
16	
17	  it("Rule 2 (Survival): in row ### at y=0 plus cell (1,2), the center cell (1,0) has 3 live neighbors and survives — next gen contains (1,0)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 2]]);
19	    expect(result).toContainEqual([1, 0]);
20	  });
21	
22	  it("Rule 3 (Overpopulation): in a full 3x3 grid, the center cell (1,1) has 4 neighbors and dies — (1,1) is not in next gen", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [0, 1], [1, 1], [2, 1], [0, 2], [1, 2], [2, 2]]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	
27	  it("Rule 4 (Reproduction): L-shape [(0,2),(1,2),(0,1)] — dead cell (1,1) has exactly 3 neighbors and becomes alive — next gen contains (1,1)", () => {
28	    const result = nextGeneration([[0, 2], [1, 2], [0, 1]]);
29	    expect(result).toContainEqual([1, 1]);
30	  });
31	
32	  it("Block still life: [(0,0),(1,0),(0,1),(1,1)] remains unchanged after one generation", () => {
33	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
34	    const result = nextGeneration(input);
35	    expect(result).toHaveLength(4);
36	    expect(new Set(result.map(c => c.join(",")))).toEqual(new Set(input.map(c => c.join(","))));
37	  });
38	
39	  it.todo("Blinker oscillator: vertical [(0,0),(0,1),(0,2)] becomes horizontal [(-1,1),(0,1),(1,1)]");
40	
41	  it.todo("Blinker oscillator: horizontal [(-1,1),(0,1),(1,1)] returns to vertical [(0,0),(0,1),(0,2)] (period 2)");
42	
