1	type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const toKey = ([x, y]: Cell): string => `${x},${y}`;
10	const fromKey = (key: string): Cell => {
11	  const [x, y] = key.split(",");
12	  return [Number(x), Number(y)];
13	};
14	
15	export function nextGeneration(cells: Array<Cell>): Array<Cell> {
16	  const liveKeys = new Set(cells.map(toKey));
17	
18	  const neighborCounts = new Map<string, number>();
19	  for (const [x, y] of cells) {
20	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
21	      const key = toKey([x + dx, y + dy]);
22	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
23	    }
24	  }
25	
26	  const result: Array<Cell> = [];
27	  for (const [key, count] of neighborCounts) {
28	    const isAliveNextGen = count === 3 || (count === 2 && liveKeys.has(key));
29	    if (isAliveNextGen) {
30	      result.push(fromKey(key));
31	    }
32	  }
33	
34	  return result;
35	}
